package com.example.filetransfer;

import com.google.protobuf.ByteString;
import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.stub.StreamObserver;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.time.Duration;
import java.time.Instant;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class FileTransferServiceServer {

    private final int port;
    private final Server server;
    private final String uploadDirectory;

    public FileTransferServiceServer(int port, String uploadDirectory) {
        this.port = port;
        this.uploadDirectory = uploadDirectory;
        // Ensure the upload directory exists
        File dir = new File(uploadDirectory);
        if (!dir.exists()) {
            dir.mkdirs();
        }

        server = ServerBuilder.forPort(port)
                .addService(new FileTransferServiceImpl())
                // Set max message size if you anticipate very large chunks (default is 4MB)
                // .maxInboundMessageSize(100 * 1024 * 1024) // e.g., 100MB
                .executor(Executors.newFixedThreadPool(4)) // Use a fixed thread pool for handling requests
                .build();
    }

    public void start() throws IOException {
        server.start();
        System.out.println("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            // Use stderr here since the logger may have been reset by its JVM shutdown hook.
            System.err.println("*** shutting down gRPC server since JVM is shutting down");
            try {
                FileTransferServiceServer.this.stop();
            } catch (InterruptedException e) {
                e.printStackTrace(System.err);
            }
            System.err.println("*** server shut down");
        }));
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }

    /**
     * Await termination on the main thread since the gRPC library uses daemon threads.
     */
    private void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        String uploadDir = "server_uploads";
        FileTransferServiceServer server = new FileTransferServiceServer(50051, uploadDir);
        server.start();
        server.blockUntilShutdown();
    }

    private class FileTransferServiceImpl extends FileTransferServiceGrpc.FileTransferServiceImplBase {

        @Override
        public StreamObserver<FileUploadRequest> transferFile(StreamObserver<FileTransferResponse> responseObserver) {
            return new StreamObserver<FileUploadRequest>() {
                private String filename = null;
                private FileOutputStream fileOutputStream = null;
                private long bytesReceived = 0;
                private Instant startTime;
                private boolean transferInitiated = false;

                @Override
                public void onNext(FileUploadRequest request) {
                    if (request.hasMetadata()) {
                        // This is the first message: file metadata
                        if (transferInitiated) {
                            // Already received metadata, unexpected subsequent metadata
                            responseObserver.onError(new IllegalStateException("Received multiple metadata messages for a single transfer."));
                            return;
                        }
                        FileMetadata metadata = request.getMetadata();
                        filename = metadata.getFilename();
                        try {
                            File outputFile = new File(uploadDirectory, filename);
                            fileOutputStream = new FileOutputStream(outputFile);
                            startTime = Instant.now();
                            transferInitiated = true;
                            System.out.println(Thread.currentThread().getName() + ": Starting file transfer for: " + filename + " (size: " + metadata.getFileSize() + " bytes)");
                            responseObserver.onNext(FileTransferResponse.newBuilder()
                                    .setStatus(FileTransferResponse.Status.IN_PROGRESS)
                                    .setMessage("Ready to receive: " + filename)
                                    .build());
                        } catch (IOException e) {
                            System.err.println(Thread.currentThread().getName() + ": Error creating file " + filename + ": " + e.getMessage());
                            responseObserver.onError(e);
                        }
                    } else if (request.hasChunkData()) {
                        // Subsequent messages: data chunks
                        if (!transferInitiated || fileOutputStream == null) {
                            responseObserver.onError(new IllegalStateException("File metadata not received or file output stream not initialized before receiving data chunks."));
                            return;
                        }
                        ByteString chunk = request.getChunkData();
                        try {
                            chunk.writeTo(fileOutputStream);
                            bytesReceived += chunk.size();
                            // Optionally send progress updates
                            if (bytesReceived % (10 * 1024 * 1024) < chunk.size() && bytesReceived > 0) { // Every 10MB mark
                                System.out.println(Thread.currentThread().getName() + ": Received " + (bytesReceived / (1024 * 1024)) + "MB for " + filename);
                                responseObserver.onNext(FileTransferResponse.newBuilder()
                                        .setStatus(FileTransferResponse.Status.IN_PROGRESS)
                                        .setMessage("Received " + bytesReceived + " bytes")
                                        .setBytesProcessed(bytesReceived)
                                        .build());
                            }
                        } catch (IOException e) {
                            System.err.println(Thread.currentThread().getName() + ": Error writing chunk to file " + filename + ": " + e.getMessage());
                            responseObserver.onError(e);
                        }
                    } else {
                        System.err.println(Thread.currentThread().getName() + ": Received unknown payload type.");
                        responseObserver.onError(new IllegalArgumentException("Unknown payload type in FileUploadRequest."));
                    }
                }

                @Override
                public void onError(Throwable t) {
                    System.err.println(Thread.currentThread().getName() + ": File transfer for " + filename + " failed: " + t.getMessage());
                    cleanupStream(true);
                    responseObserver.onNext(FileTransferResponse.newBuilder()
                            .setStatus(FileTransferResponse.Status.FAILED)
                            .setMessage("Transfer failed: " + t.getMessage())
                            .setBytesProcessed(bytesReceived)
                            .build());
                    responseObserver.onCompleted();
                }

                @Override
                public void onCompleted() {
                    System.out.println(Thread.currentThread().getName() + ": Client stream completed for " + filename);
                    cleanupStream(false);
                    Instant endTime = Instant.now();
                    long durationMillis = Duration.between(startTime, endTime).toMillis();
                    double speedMbps = 0;
                    if (durationMillis > 0) {
                        speedMbps = (double) bytesReceived * 8 / (durationMillis / 1000.0) / (1024 * 1024);
                    }

                    if (transferInitiated) {
                        System.out.println(Thread.currentThread().getName() + ": File transfer for " + filename + " completed. Total bytes: " + bytesReceived +
                                ", took: " + durationMillis + "ms, Speed: " + String.format("%.2f", speedMbps) + " Mbps");
                        responseObserver.onNext(FileTransferResponse.newBuilder()
                                .setStatus(FileTransferResponse.Status.COMPLETED)
                                .setMessage("File transfer completed successfully. Total bytes: " + bytesReceived)
                                .setBytesProcessed(bytesReceived)
                                .build());
                    } else {
                        System.out.println(Thread.currentThread().getName() + ": No file was transferred or stream was empty.");
                        responseObserver.onNext(FileTransferResponse.newBuilder()
                                .setStatus(FileTransferResponse.Status.COMPLETED) // Or FAILED if no data was strictly an error
                                .setMessage("No file data received. Stream completed.")
                                .setBytesProcessed(bytesReceived)
                                .build());
                    }
                    responseObserver.onCompleted();
                }

                private void cleanupStream(boolean isError) {
                    if (fileOutputStream != null) {
                        try {
                            fileOutputStream.close();
                            if (isError && filename != null) {
                                // Optionally delete partially uploaded file on error
                                File partialFile = new File(uploadDirectory, filename);
                                if (partialFile.exists()) {
                                    System.err.println(Thread.currentThread().getName() + ": Deleting partial file " + filename);
                                    partialFile.delete();
                                }
                            }
                        } catch (IOException e) {
                            System.err.println(Thread.currentThread().getName() + ": Error closing file stream during cleanup for " + filename + ": " + e.getMessage());
                        } finally {
                            fileOutputStream = null;
                            filename = null;
                            bytesReceived = 0;
                            startTime = null;
                            transferInitiated = false;
                        }
                    }
                }
            };
        }
    }
}

// FileTransferServiceClient.java
package com.example.filetransfer;

import com.google.protobuf.ByteString;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.logging.Level;
import java.util.logging.Logger;

public class FileTransferServiceClient {
    private static final Logger logger = Logger.getLogger(FileTransferServiceClient.class.getName());

    private final ManagedChannel channel;
    private final FileTransferServiceGrpc.FileTransferServiceStub asyncStub;

    public FileTransferServiceClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext() // For demonstration, use plaintext. In production, use TLS.
                // Set max message size if you anticipate very large chunks (default is 4MB)
                // .maxInboundMessageSize(100 * 1024 * 1024) // e.g., 100MB for server responses
                .build();
        asyncStub = FileTransferServiceGrpc.newStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void uploadFile(String filePath) {
        File file = new File(filePath);
        if (!file.exists() || !file.isFile()) {
            logger.log(Level.SEVERE, "File not found or not a regular file: {0}", filePath);
            return;
        }

        final CountDownLatch finishLatch = new CountDownLatch(1);

        // This is the observer for server responses
        StreamObserver<FileTransferResponse> serverResponseObserver = new StreamObserver<FileTransferResponse>() {
            @Override
            public void onNext(FileTransferResponse response) {
                logger.log(Level.INFO, "Server Status: {0} - {1}", new Object[]{response.getStatus(), response.getMessage()});
                if (response.hasBytesProcessed() && response.getBytesProcessed() > 0) {
                    double progress = (double) response.getBytesProcessed() / file.length() * 100;
                    logger.log(Level.INFO, String.format("Upload Progress: %.2f%%", progress));
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Server error during file transfer: " + t.getMessage(), t);
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Server stream completed (transfer finished or server acknowledged).");
                finishLatch.countDown();
            }
        };

        // This is the observer for client requests (to send to server)
        StreamObserver<FileUploadRequest> requestObserver = asyncStub.transferFile(serverResponseObserver);

        try (FileInputStream fileInputStream = new FileInputStream(file)) {
            // 1. Send file metadata as the first message
            FileMetadata metadata = FileMetadata.newBuilder()
                    .setFilename(file.getName())
                    .setFileSize(file.length())
                    .build();
            requestObserver.onNext(FileUploadRequest.newBuilder().setMetadata(metadata).build());
            logger.info("Sent file metadata: " + file.getName());

            // 2. Send file data chunks
            // Choose a chunk size that balances network overhead and memory usage.
            // gRPC default max message size is 4MB. Chunks should ideally be smaller.
            // Here we use 1MB chunks.
            byte[] buffer = new byte[1024 * 1024]; // 1MB chunks
            int bytesRead;
            long totalBytesSent = 0;
            while ((bytesRead = fileInputStream.read(buffer)) != -1) {
                FileUploadRequest chunk = FileUploadRequest.newBuilder()
                        .setChunkData(ByteString.copyFrom(buffer, 0, bytesRead))
                        .build();
                requestObserver.onNext(chunk);
                totalBytesSent += bytesRead;
                // Optional: add a small delay for very high-speed local tests to simulate network latency
                // Thread.sleep(1);
            }

            // 3. Signal completion of client's outgoing stream
            requestObserver.onCompleted();
            logger.info("Client finished sending file data for: " + file.getName() + ", total bytes sent: " + totalBytesSent);

            // Wait for the server to send its final response or complete its stream
            if (!finishLatch.await(10, TimeUnit.MINUTES)) { // Wait up to 10 minutes for server response
                logger.log(Level.WARNING, "Upload did not finish in time for file: " + file.getName());
            }
        } catch (IOException e) {
            logger.log(Level.SEVERE, "Error during file upload: " + e.getMessage(), e);
            requestObserver.onError(e); // Inform server about client-side error
        } catch (InterruptedException e) {
            logger.log(Level.SEVERE, "Client thread interrupted: " + e.getMessage(), e);
            Thread.currentThread().interrupt(); // Restore interrupt status
            requestObserver.onError(e); // Inform server about client-side error
        } finally {
            // If the latch hasn't counted down, ensure it does (e.g., in case of unexpected exceptions)
            finishLatch.countDown();
        }
    }

    public static void main(String[] args) throws InterruptedException {
        FileTransferServiceClient client = new FileTransferServiceClient("localhost", 50051);
        try {
            // Create a dummy file for testing.
            // You can replace this with any existing file path.
            String testFilePath = "test_file.bin";
            long fileSize = 50 * 1024 * 1024; // 50MB
            createDummyFile(testFilePath, fileSize);

            logger.info("Attempting to upload file: " + testFilePath);
            client.uploadFile(testFilePath);
            logger.info("Upload process initiated for " + testFilePath + ". Waiting for server response...");

        } finally {
            client.shutdown();
        }
    }

    private static void createDummyFile(String filename, long size) {
        File file = new File(filename);
        if (file.exists() && file.length() == size) {
            logger.info("Dummy file already exists and has correct size: " + filename);
            return;
        }
        logger.info("Creating dummy file: " + filename + " with size: " + (size / (1024 * 1024)) + "MB");
        try (FileOutputStream fos = new FileOutputStream(file)) {
            byte[] data = new byte[1024 * 1024]; // 1MB buffer
            for (int i = 0; i < data.length; i++) {
                data[i] = (byte) (i % 256); // Fill with some arbitrary data
            }
            long bytesWritten = 0;
            while (bytesWritten < size) {
                int bytesToWrite = (int) Math.min(data.length, size - bytesWritten);
                fos.write(data, 0, bytesToWrite);
                bytesWritten += bytesToWrite;
            }
            logger.info("Dummy file created successfully: " + filename);
        } catch (IOException e) {
            logger.log(Level.SEVERE, "Error creating dummy file: " + e.getMessage(), e);
        }
    }
}